```class Solution {
public:
    int numberOfStableArrays(int zero, int one, int limit) {
        const int MOD = 1e9 + 7;
        int dp[2][201][201] = {};
        dp[0][1][0] = 1;
        dp[1][0][1] = 1;
        for (int i = 1; i <= limit; ++i) {
            for (int j = 1; j <= zero; ++j) {
                for (int k = 1; k <= one; ++k) {
                    dp[0][j][k] = (dp[0][j][k] + dp[1][j][k-1]) % MOD;
                    if (j > 1) dp[0][j][k] = (dp[0][j][k] + dp[1][j-1][k]) % MOD;
                }
            }
        }
        int res = 0;
        for (int i = 1; i <= zero; ++i) {
            for (int j = 1; j <= one; ++j) {
                res = (res + dp[0][i][j] + dp[1][i][j]) % MOD;
            }
        }
        return res;
    }
};
